#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        if(N==3){
            printf("-1\n");
            continue;
        }
        if(N==4){
            printf("1 4 2 3\n");
            continue;
        }
        // N >= 5
        int first[5] = {5,1,2,4,3};
        for(int i=0;i<5 && i<N;i++){
            if(i) printf(" ");
            printf("%d",first[i]);
        }
        for(int i=6;i<=N;i++){
            printf(" %d",i);
        }
        printf("\n");
    }
    return 0;
}

